// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class LearnedQueryJoinOptimizerHighUncertaintyFallbackTest {

	@Test
	void enablesFallbackForHighUncertaintyDpPlans() {
		assertTrue(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyGreedyFallback("dp", 7, 7.0d));
	}

	@Test
	void doesNotFallbackForNonDpPlanner() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyGreedyFallback("greedy", 7, 7.0d));
	}

	@Test
	void doesNotFallbackForLowOperandCount() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyGreedyFallback("dp", 5, 7.0d));
	}

	@Test
	void doesNotFallbackForLowOrInvalidUncertainty() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyGreedyFallback("dp", 7, 5.0d));
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyGreedyFallback("dp", 7, Double.NaN));
	}

	@Test
	void enablesLegacyFallbackForFullyUncertainHighCardinalityDpPlan() {
		assertTrue(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 7.0d, 20000.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForFullyUncertainLowCardinalityDpPlan() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 7.0d, 200.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForInvalidCardinalitySignals() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 7.0d, Double.NaN));
		assertFalse(
				LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 7.0d,
						Double.POSITIVE_INFINITY));
		assertFalse(
				LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 7.0d,
						Double.NEGATIVE_INFINITY));
	}

	@Test
	void doesNotEnableLegacyFallbackWhenUncertaintyBelowFractionThreshold() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 7, 6.0d, 20000.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForSmallFullyUncertainLargeCardinalityDpPlan() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 3, 3.0d, 20000.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForSmallFullyUncertainLargeCardinalityGreedyPlan() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("greedy", 2, 2.0d, 20000.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForSmallFullyUncertainLowCardinalityGreedyPlan() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("greedy", 2, 2.0d, 100.0d));
	}

	@Test
	void doesNotEnableLegacyFallbackForSmallFullyUncertainLowCardinalityDpPlan() {
		assertFalse(LearnedQueryJoinOptimizer.shouldUseHighUncertaintyLegacyFallback("dp", 3, 3.0d, 5000.0d));
	}
}
